&lt;p&gt;&lt;strong&gt;&lt;span data-contrast=&quot;auto&quot;&gt;😄&lt;/span&gt;&lt;/strong&gt;&lt;strong&gt; &lt;/strong&gt;&lt;span data-contrast=&quot;auto&quot;&gt;An awesome team (not everybody like our jokes, but we try our best)&lt;/span&gt;&lt;span data-ccp-props=&quot;{&amp;quot;201341983&amp;quot;:0,&amp;quot;335559739&amp;quot;:0,&amp;quot;335559740&amp;quot;:240}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
